external_knowledge:
External knowledge is not explicitly required in this case, but for better understanding: 
- A vector type could be Mammalian or Baculovirus; 
- Virology is a department that deals with the study of viruses.

sql:
SELECT vector_id, title, quantity
FROM vectors
WHERE vector_type IN ('Mammalian', 'Baculovirus') AND quantity > 1;

SELECT storage_location, COUNT(vector_id) AS total_vectors_stored
FROM vector_storage
GROUP BY storage_location;

SELECT COUNT(*)
FROM research_requests
WHERE status = 'pending';

SELECT request_date, COUNT(request_id) AS total_requests
FROM research_requests
GROUP BY request_date;

SELECT status
FROM research_requests
WHERE request_id = 6;

SELECT quantity 
FROM vector_storage 
WHERE storage_location = 'Freezer 1';

SELECT DISTINCT v.expressed_protein, vs.storage_location, vs.quantity 
FROM vectors v 
JOIN vector_storage vs ON v.vector_id = vs.vector_id;

SELECT COUNT(DISTINCT vector_id) AS unique_mammalian_vectors
FROM vectors
WHERE vector_type = 'Mammalian';

SELECT MIN(v.vector_id) AS vector_id, MIN(v.title) AS title, v.expressed_protein, SUM(v.quantity) AS total_quantity
FROM vectors v
GROUP BY v.expressed_protein;

SELECT SUM(quantity) AS total_quantity
FROM research_requests
WHERE user_id = 101;

SELECT COUNT(DISTINCT rr.vector_id) 
FROM research_requests rr 
WHERE rr.status = 'pending';
